mapper.select:
/* 아이템(도면,문서,SW) 파일 정보 조회 */
SELECT FILE_PATH_NM 	AS filePath
, FILE_NM			AS fileNm
, ORG_FILE_NM		AS fileOrgNm

	FROM DOCS_DOCUMENT_FILE


	FROM DOCS_SW_FILE


	FROM DOCS_DRAWING

WHERE OBJECT_ID = #{objectId}

	AND FILE_NO = #{fileNo}

SELECT FILE_PATH AS filePath
	 , FILE_UPLOAD_NM AS fileNm
	 , FILE_NM AS fileOrgNm
FROM DOCS_FILE
WHERE FILE_CD = #{objectId}
  AND FILE_NO = #{fileNo}

/* 아이템(도면,문서,SW) 파일 정보 조회 */ SELECT fileInfo.FILE_PATH_NM AS filePath , fileInfo.FILE_NM AS fileNm , fileInfo.ORG_FILE_NM AS fileOrgNm
, info.PROTECT_YN AS protectYn FROM DOCS_DOCUMENT_FILE fileInfo JOIN DOCS_DOCUMENT info ON fileInfo.OBJECT_ID = info.OBJECT_ID
, info.PROTECT_YN AS protectYn FROM ( SELECT OBJECT_ID, OBJECT_ID AS PARENT_OBJECT_ID, FILE_NO, FILE_PATH_NM, FILE_NM, ORG_FILE_NM FROM DOCS_SW_FILE UNION ALL SELECT OBJECT_ID, PARENT_OBJECT_ID, FILE_NO, FILE_PATH_NM, ORG_FILE_NM AS FILE_NM, ORG_FILE_NM FROM DOCS_SW_SUB_FILE WHERE COALESCE(USE_YN, 'Y') = 'Y' ) fileInfo JOIN DOCS_SW info ON fileInfo.PARENT_OBJECT_ID = info.OBJECT_ID
, fileInfo.PROTECT_YN AS protectYn FROM DOCS_DRAWING fileInfo
WHERE fileInfo.OBJECT_ID = #{objectId}
AND fileInfo.FILE_NO = #{fileNo}

/* 미등록자료 파일 정보 조회  */
SELECT FILE_PATH AS filePath
	 , FILE_NM AS fileNm
	 , FILE_UPLOAD_NM AS fileOrgNm
FROM DOCS_FILE
WHERE FILE_CD = #{objectId}
  AND FILE_NO = #{fileNo}

/* 생산기술자료 파일 정보 조회 */
SELECT FILE_PATH_NM AS filePath
, FILE_NM AS fileNm
, ORG_FILE_NM AS fileOrgNm

	FROM DOCS_PRODUCT_DOCUMENT_FILE


	FROM DOCS_PRODUCT_SW_FILE

WHERE OBJECT_ID = #{objectId}
AND FILE_NO = #{fileNo}

SELECT LANG_DESC
FROM DOCS_LANG
WHERE LANG_CD = #{msgCode}
  AND LANG_TYPE = #{sessionLang}

/* 배포된 아이템 파일 정보 조회 */ SELECT fileInfo.FILE_NM AS fileNm , fileInfo.ORG_FILE_NM AS fileOrgNm , fileInfo.FILE_NO AS fileNo , fileInfo.OBJECT_ID AS objectId , fileInfo.REQUEST_NO AS requestNo , objectInfo.SECURITY_TYPE_CD AS securityTypeCd , request.INSERT_USER_CD AS requestUserCd , request.REQUEST_TYPE AS requestType , request.OBJECT_TYPE AS objectType , COALESCE(request.PROTECT_YN, 'N') AS protectYn FROM DOCS_REQUEST_FILE fileInfo JOIN DOCS_REQUEST_MAPPING reqMap ON fileInfo.REQUEST_NO = reqMap.REQUEST_NO AND fileInfo.OBJECT_ID = reqMap.OBJECT_ID
JOIN DOCS_PRODUCT_DOCUMENT objectInfo ON fileInfo.OBJECT_ID = objectInfo.OBJECT_ID
JOIN DOCS_PRODUCT_SW objectInfo ON fileInfo.OBJECT_ID = objectInfo.OBJECT_ID
JOIN DOCS_REQUEST request ON request.REQUEST_NO = fileInfo.REQUEST_NO WHERE fileInfo.REQUEST_NO = #{requestNo} AND fileInfo.OBJECT_ID = #{objectId}

mapper.update:
UPDATE DOCS_REQUEST_FILE
SET PRINT_COUNT = (SELECT CAST(PRINT_COUNT AS INTEGER) + 1
				   FROM DOCS_REQUEST_FILE
				   WHERE REQUEST_NO = #{requestNo}
					 AND OBJECT_ID = #{objectId}
					 AND FILE_NO = #{fileNo} )
WHERE REQUEST_NO = #{requestNo}
  AND OBJECT_ID = #{objectId}
  AND FILE_NO = #{fileNo}
